"""## Elección de número de clusters"""

from sklearn.cluster import KMeans
import matplotlib.pyplot as plt
import numpy as np

# Use only scaled numeric data
X = mx_empresas.select_dtypes(include="number").values

inertia = []
k_range = range(2, 15)

for k in k_range:
    kmeans = KMeans(
        n_clusters=k,
        random_state=42,
        n_init=20
    )
    kmeans.fit(X)
    inertia.append(kmeans.inertia_)

# Plot Elbow
plt.figure()
plt.plot(k_range, inertia, marker="o")

plt.title("Elbow Method - mx_empresas")
plt.xlabel("Number of Clusters (k)")
plt.ylabel("Inertia")

plt.xticks(k_range)
plt.show()

from sklearn.cluster import KMeans
from sklearn.metrics import silhouette_score
import matplotlib.pyplot as plt
import numpy as np

# Use only numeric variables
X = mx_empresas.select_dtypes(include="number").values

silhouette_scores = []
k_range = range(2, 15)

for k in k_range:
    kmeans = KMeans(
        n_clusters=k,
        random_state=42,
        n_init=20
    )
    kmeans.fit(X)

    score = silhouette_score(
        X,
        kmeans.labels_,
        metric="euclidean"
    )

    silhouette_scores.append(score)

# Plot Silhouette Curve
plt.figure()
plt.plot(k_range, silhouette_scores, marker="o")

plt.title("Silhouette Method - mx_empresas")
plt.xlabel("Number of Clusters (k)")
plt.ylabel("Silhouette Score")

plt.xticks(k_range)
plt.show()

