import numpy as np
import pandas as pd
import plotly.graph_objects as go
from sklearn.decomposition import PCA

# -------------------------
# 1) Preparar datos (ya escalados)
# -------------------------
num_cols = mx_empresas.select_dtypes(include="number").columns.tolist()
if "cluster_label" in num_cols:
    num_cols.remove("cluster_label")

X = mx_empresas[num_cols].copy()

# Si hay NA, quitarlos (o cambia por imputación si prefieres)
mask = ~X.isna().any(axis=1)
X = X.loc[mask]
df_plot = mx_empresas.loc[mask].copy()

# -------------------------
# 2) PCA 3D
# -------------------------
pca = PCA(n_components=3, random_state=42)
X_pca = pca.fit_transform(X.values)

df_plot["PC1"] = X_pca[:, 0]
df_plot["PC2"] = X_pca[:, 1]
df_plot["PC3"] = X_pca[:, 2]

# -------------------------
# 3) Loadings (vectores)
# -------------------------
loadings = pd.DataFrame(
    pca.components_.T,
    columns=["PC1", "PC2", "PC3"],
    index=num_cols
)

# Escala visual de flechas (ajusta si quedan muy grandes/chicas)
arrow_scale = 3.0

# -------------------------
# 4) Plot 3D: puntos + vectores
# -------------------------
fig = go.Figure()

# Puntos (clusters)
if "cluster_label" in df_plot.columns:
    for c in sorted(df_plot["cluster_label"].dropna().unique()):
        tmp = df_plot[df_plot["cluster_label"] == c]
        fig.add_trace(go.Scatter3d(
            x=tmp["PC1"],
            y=tmp["PC2"],
            z=tmp["PC3"],
            mode="markers",
            name=f"Cluster {c}",
            marker=dict(size=4, opacity=0.75),
            text=tmp["empresa"] if "empresa" in tmp.columns else None,
            hovertemplate=(
                "PC1=%{x:.3f}<br>PC2=%{y:.3f}<br>PC3=%{z:.3f}"
                + ("<br>%{text}" if "empresa" in tmp.columns else "")
                + "<extra></extra>"
            )
        ))
else:
    fig.add_trace(go.Scatter3d(
        x=df_plot["PC1"], y=df_plot["PC2"], z=df_plot["PC3"],
        mode="markers",
        name="Observaciones",
        marker=dict(size=4, opacity=0.75)
    ))

# Vectores (loadings) desde el origen
for feature in loadings.index:
    x, y, z = loadings.loc[feature, ["PC1", "PC2", "PC3"]].values * arrow_scale
    fig.add_trace(go.Scatter3d(
        x=[0, x],
        y=[0, y],
        z=[0, z],
        mode="lines+text",
        text=[None, feature],
        line=dict(width=6),
        showlegend=False,
        hoverinfo="skip"
    ))

fig.update_layout(
    title="PCA 3D + Clusters + Vectores de Loadings",
    scene=dict(
        xaxis_title="PC1",
        yaxis_title="PC2",
        zaxis_title="PC3"
    )
)

fig.show()

"""Mejoremos la legibilidad de esto"""

# Calcular magnitud total de cada vector
loadings["magnitude"] = np.sqrt(
    loadings["PC1"]**2 +
    loadings["PC2"]**2 +
    loadings["PC3"]**2
)

# Quedarnos con las 6 más importantes
top_n = 6
top_features = loadings.sort_values("magnitude", ascending=False).head(top_n)

top_features

short_names = {
    "ventas_anuales_musd": "Ventas",
    "volumen_exportaciones_musd": "Volumen Exp",
    "frecuencia_exportacion_dias": "Frecuencia",
    "participacion_mercado": "Market Share",
    "reporte_esg": "ESG",
    "presencia_internacional": "Internacional"
}

arrow_scale = 2.0

fig = go.Figure()

# --- Puntos por cluster ---
for c in sorted(df_plot["cluster_label"].unique()):
    tmp = df_plot[df_plot["cluster_label"] == c]
    fig.add_trace(go.Scatter3d(
        x=tmp["PC1"],
        y=tmp["PC2"],
        z=tmp["PC3"],
        mode="markers",
        name=f"Cluster {c}",
        marker=dict(size=5, opacity=0.7)
    ))

# --- Solo top variables ---
for feature in top_features.index:
    x, y, z = top_features.loc[feature, ["PC1", "PC2", "PC3"]].values * arrow_scale
    label = short_names.get(feature, feature)

    fig.add_trace(go.Scatter3d(
        x=[0, x],
        y=[0, y],
        z=[0, z],
        mode="lines+text",
        text=[None, label],
        line=dict(width=6),
        showlegend=False
    ))

fig.update_layout(
    title="PCA 3D Biplot (Top Variables)",
    scene=dict(
        xaxis_title="PC1",
        yaxis_title="PC2",
        zaxis_title="PC3"
    )
)

fig.show()

"""# **Análisis de 2 componentes**"""

import numpy as np
import pandas as pd
import plotly.graph_objects as go
from sklearn.decomposition import PCA

# -------------------------
# 1) Preparar datos
# -------------------------
num_cols = mx_empresas.select_dtypes(include="number").columns.tolist()
if "cluster_label" in num_cols:
    num_cols.remove("cluster_label")

X = mx_empresas[num_cols].copy()
mask = ~X.isna().any(axis=1)
X = X.loc[mask]
df_plot = mx_empresas.loc[mask].copy()

# -------------------------
# 2) PCA con 2 componentes
# -------------------------
pca_2d = PCA(n_components=2, random_state=42)
X_pca_2d = pca_2d.fit_transform(X.values)

df_plot["PC1"] = X_pca_2d[:, 0]
df_plot["PC2"] = X_pca_2d[:, 1]

# -------------------------
# 3) Loadings
# -------------------------
loadings_2d = pd.DataFrame(
    pca_2d.components_.T,
    columns=["PC1", "PC2"],
    index=num_cols
)

# Magnitud para seleccionar variables más importantes
loadings_2d["magnitude"] = np.sqrt(
    loadings_2d["PC1"]**2 + loadings_2d["PC2"]**2
)

top_n = 5
top_features = loadings_2d.sort_values("magnitude", ascending=False).head(top_n)

# -------------------------
# 4) Plot
# -------------------------
fig = go.Figure()

# Puntos por cluster
for c in sorted(df_plot["cluster_label"].unique()):
    tmp = df_plot[df_plot["cluster_label"] == c]
    fig.add_trace(go.Scatter(
        x=tmp["PC1"],
        y=tmp["PC2"],
        mode="markers",
        name=f"Cluster {c}",
        text=tmp["empresa"],
        hovertemplate="Empresa: %{text}<br>PC1=%{x:.2f}<br>PC2=%{y:.2f}<extra></extra>"
    ))

# Vectores
arrow_scale = 2.5

for feature in top_features.index:
    x, y = top_features.loc[feature, ["PC1", "PC2"]] * arrow_scale

    fig.add_trace(go.Scatter(
        x=[0, x],
        y=[0, y],
        mode="lines+text",
        text=[None, feature],
        showlegend=False
    ))

fig.update_layout(
    title="PCA 2D Biplot (Clusters + Variables Clave)",
    xaxis_title=f"PC1 ({pca_2d.explained_variance_ratio_[0]*100:.1f}% var)",
    yaxis_title=f"PC2 ({pca_2d.explained_variance_ratio_[1]*100:.1f}% var)"
)

fig.show()

# Varianza total explicada
print("Varianza explicada total:",
      np.sum(pca_2d.explained_variance_ratio_))

